var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이 정도로는 날 쓰러트릴 수 없다!","JPN":"その程度では私は倒せない！","ENG":"You'll have to do better than this!","TWN":"這種程度可沒辦法讓我倒下！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"죽어라! 괴물!","JPN":"死ぬがいい！　化け物！","ENG":"Die! Monster!","TWN":"去死吧！怪物！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......크윽.","JPN":"くうっ……","ENG":"Ugh.","TWN":"……咳咳。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"약해졌다고는 해도 확실히 단단하군.","JPN":"弱くなったとはいえ、堅さは間違いないな。","ENG":"It might have become weaker, but it's still as tough as ever.","TWN":"雖然它變弱了，但還是很堅硬啊。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"내 전력으로도 놈의 중추를 파괴하는 건 무리인 건가?","JPN":"私の全力でも奴の中枢を破壊するのは無理なのか？","ENG":"Is my full power not enough to destroy its core?","TWN":"靠我的戰鬥力也沒辦法破壞它的中樞神經嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아니, 아무것도 바뀐 건 없다.","JPN":"いや、何も変わったことはない。","ENG":"No, nothing has changed.","TWN":"不，我絕不會動搖。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"열번이든 백번이든, 파괴될 때까지 공격할 뿐!","JPN":"10回でも100回でも、破壊できるまで攻撃するのみ！","ENG":"Ten times, a hundred times; I'll keep attacking until it's destroyed!","TWN":"不管是十次還是一百次，攻擊到破壞它為止！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"부사령관님! 피하세요!","JPN":"副司令官！　避けてください！","ENG":"Deputy Commander! Get away from here!","TWN":"副司令官大人！快躲開！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"너야말로 물러서라! 제이나! 넌 몸도 정상이 아니야!","JPN":"お前こそ下がれ！ ジェイナ、お前は万全ではない！","ENG":"No, YOU back off, Jaina! You're not in your best condition!","TWN":"還是你走吧！婕娜！你現在的身體狀態很不好！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"더 이상 힘을 썼다간 CRF가 고갈될 거다! 그림자로 변할 수도 있어!","JPN":"これ以上力を使うとCRFが枯渇するぞ！　シャドウになりたいのか！？","ENG":"You'll deplete your CRF if you use any more power! You could turn into a Shadow!","TWN":"如果繼續戰鬥，CRF會枯竭的！你可能會變成暗影！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"처음 만났을 때 말했었지? 내가 널 퇴치하도록 만들지 마라!","JPN":"初めて会った時に言ったはずだ。私に退治される羽目になりたくなければ、大人しく待機しろ！","ENG":"Remember what I told you when we first met? Don't make me exterminate you!","TWN":"第一次見面時，我就跟你說過吧？別讓我有出手消滅你的那天！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"부사령관님이야 말로 제가 왜 이런 무저갱에 떨어졌다고 생각하시는 겁니까?!","JPN":"副司令官こそ、なぜ私がこんな地獄の底のような場所に落ちたと思っているのですか？","ENG":"No, you're the one who doesn't understand why I fell into this bottomless pit!","TWN":"副司令官大人您覺得當初為什麼我選擇進入這個無底洞？！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"당신을 살리기 위해서였어요!","JPN":"あなたに生きてほしいからです！","ENG":"It was to save you!","TWN":"是為了救你！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"그 모든 걸 헛되게 만드는 건...... 제가 용납하지 않겠습니다!","JPN":"そのすべてを無駄にすることは……私が許せません！","ENG":"I won't let everything I've been through go to waste!","TWN":"別讓我的心血白費…… 我絕不接受！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"덤벼! 이 괴물아! 널 여기로 추락시킨 건 나다!!","JPN":"かかってきなさい、この化け物！　お前をここに落としたのは私だ！","ENG":"Come at me, you monster! I'm the one who put you here!","TWN":"來吧！你這個怪物！讓你墜落到這裡的人是我！！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"제이나! 멈춰!!","JPN":"ジェイナ！　やめろ！","ENG":"Jaina! Stop!","TWN":"婕娜！快停下！！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}}]`);export{e as default};